class Node:
    def __init__(self, char):
        self.char = char.lower()
        self.left = None
        self.right = None

class BinarySearchTree:
    def __init__(self):
        self.root = None

    def insert(self, char):
        if self.root is None:
            self.root = Node(char)
        else:
            self._insert_recursive(self.root, char)

    def _insert_recursive(self, node, char):
        if char < node.char:
            if node.left is None:
                node.left = Node(char)
            else:
                self._insert_recursive(node.left, char)
        elif char > node.char:
            if node.right is None:
                node.right = Node(char)
            else:
                self._insert_recursive(node.right, char)
        # If equal, do not insert to avoid duplicates

def process_sequence(sequence):
    bst = BinarySearchTree()
    def process_char(index):
        if index >= len(sequence):
            return
        char = sequence[index]
        bst.insert(char)
        process_char(index + 1)
    process_char(0)

